    Examples:
    match_parens(['()(', ')']) == 'Yes'
    match_parens([')', ')']) == 'No'
    '''
    result = []
    for c in lst:
        if c == ')':
            if len(result) == 0:
                return 'No'
            if result[-1] == '(':
                result.pop()
            else:
                result.append(c)
        else:
            result.append(c)
    if len(result) == 0:
        return 'Yes'
    else:
        return 'No'

